module top_module (
    input clk,
    input reset,
    input t,
    output q );reg q_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q_reg <= 1'b0;
        else if (t)
            q_reg <= ~q_reg;
    end

    assign q = q_reg;

endmodule
